num_layers = len(rank_distribution)
num_ranks = 20

results = []

for layer_idx, dist in enumerate(rank_distribution):
    # 构建完整的百分比数组 (rank 1~20)
    pcts = []
    for r in range(1, num_ranks + 1):
        pcts.append(dist.get(f"rank{r}", 0.0))

    # Top-k accuracy (%), k = 1~5
    topk = [sum(pcts[:k]) for k in range(1, 6)]

    # Mean rank (加权)
    mean = sum((r + 1) * (pcts[r] / 100.0) for r in range(num_ranks))

    results.append((layer_idx, mean, *topk))

# 按 mean rank 从小到大排序，只取 top-5 层
results.sort(key=lambda x: x[1])
results = results[:32]

# 输出 LaTeX 格式
for row in results:
    layer_idx, mean, t1, t2, t3, t4, t5 = row
    print(f"{layer_idx} & {mean:.2f} & {t1:.1f}\\% & {t2:.1f}\\% & {t3:.1f}\\% & {t4:.1f}\\% & {t5:.1f}\\% \\\\")
